import React, { useState } from 'react';
import { AsyncStorage } from 'react-native';

// Login screen component
const LoginScreen = ({ navigation }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = async () => {
    // Simulate login with fake data
    const userData = { name: 'John Doe', email };
    const authToken = 'fakeAuthToken';

    await AsyncStorage.setItem('authToken', authToken);
    await AsyncStorage.setItem('userData', JSON.stringify(userData));

    navigation.navigate('Home');
  };

  return (
    <View>
      {/* Render login form */}
      <Button title="Login" onPress={handleLogin} />
    </View>
  );
};

// Home screen component
const HomeScreen = ({ navigation }) => {
  const [userData, setUserData] = useState(null);
  const [authToken, setAuthToken] = useState(null);

  useEffect(() => {
    const unsubscribe = navigation.addListener('focus', async () => {
      const storedAuthToken = await AsyncStorage.getItem('authToken');
      const storedUserData = await AsyncStorage.getItem('userData');

      if (storedAuthToken && storedUserData) {
        setAuthToken(storedAuthToken);
        setUserData(JSON.parse(storedUserData));
      }
    });

    return unsubscribe;
  }, [navigation]);

  const handleLogout = () => {
    AsyncStorage.removeItem('authToken');
    AsyncStorage.removeItem('userData');
    navigation.navigate('Login');
  };

  if (!userData || !authToken) return null;

  return (
    <View>
      {/* Render home screen with user data */}
      <Text>{userData.name}</Text>
      <Button title="Logout" onPress={handleLogout} />
    </View>
  );
};

// App navigation setup
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

const Stack = createStackNavigator();

function App() {
  return (
    <NavigationContainer>
      <Stack.Navigator initialRouteName="Login">
        <Stack.Screen name="Login" component={LoginScreen} />
        <Stack.Screen name="Home" component={HomeScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
}

export default App;